  ('aboriginal-a5729396-moex-00174', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列有關行政訴訟判決執行力之敘述，何者錯誤？', '["判決命債務人為一定之給付，債權人得以判決為執行名義", "債權人得向普通法院行政執行處聲請為強制執行", "債務人為中央或地方行政機關或其他公法人時，為強制執行之法院應先定相當期限通知債務人履行", "依行政訴訟法成立之和解，得為執行名義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
