  ('aboriginal-a5729396-moex-00177', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '依民事訴訟法之規定，下列關於訴訟代理之敘述，何者正確？', '["訴訟代理權因本人死亡而消滅", "訴訟代理之委任，原則上無須於每一審級為之", "訴訟代理人事實上之陳述，經到場之當事人本人即時更正者，不生效力", "關於強制執行之行為或領取所爭物，訴訟代理人無須特別委任，即得為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
