  ('aboriginal-a5729396-moex-00182', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '甲、乙、丙3人共有一地，應有部分各為三分之一，並約定由乙管理該地，嗣後甲拋棄其應有部分，而無 人繼受時，下列敘述何者正確？', '["拋棄無效", "拋棄後其應有部分歸乙、丙所有", "拋棄後其應有部分歸乙所有", "拋棄後其應有部分歸國家所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
